import java.util.ArrayList;import java.util.List;import java.util.Map;
final class PipelinePattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String code){super(code);this.code=code;}String code(){return code;}}
    @SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){List<Object>rawItems=(List<Object>)input.getOrDefault("items",List.of()),rawStages=(List<Object>)input.getOrDefault("stages",List.of());List<Integer>items=rawItems.stream().map(value->((Number)value).intValue()).toList();List<Integer>outputs=new ArrayList<>();List<String>receipts=new ArrayList<>();Integer limit=input.containsKey("consumer_limit")?((Number)input.get("consumer_limit")).intValue():null;
        for(int index=0;index<items.size();index++){if(limit!=null&&outputs.size()>=limit)return Map.of("outputs",outputs,"status","cancelled","failed_stage","none","cancelled_items",items.subList(index,items.size()),"stage_receipts",receipts,"upstream_cancelled",true);int value=items.get(index);
            for(Object raw:rawStages){String stage=String.valueOf(raw);int before=value;switch(stage){case"reject_negative"->{if(value<0){List<String>failed=new ArrayList<>(receipts);failed.add("failed:"+stage+":"+value);return Map.of("outputs",outputs,"status","failed","failed_stage",stage,"cancelled_items",items.subList(index+1,items.size()),"stage_receipts",failed,"upstream_cancelled",true);}}case"double"->value*=2;case"increment"->value++;default->throw new PatternException("unknown_stage");}receipts.add(stage+":"+before+"->"+value);}outputs.add(value);}
        return Map.of("outputs",outputs,"status","completed","failed_stage","none","cancelled_items",List.of(),"stage_receipts",receipts,"upstream_cancelled",false);}}
